import java.util.*;

class Solution {
    public static void main(String args[]) {
        Scanner in = new Scanner(System.in);
        long n = in.nextLong();

        int sum = 0;
        int evenCount = 0;

        String s = String.valueOf(n);
        for (int i = 0; i < s.length(); i++) {
            int digit = s.charAt(i) - '0';
            sum += digit;
            if (digit % 2 == 0) evenCount++;
        }

        System.out.println(sum * evenCount);
    }
}
